import sys
from collections import deque
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
class Solution:
    def __init__(self):
        self.res = []
    def inorderTraversal(self, root):
        stack = deque()
        while True:
            while root:
                stack.append(root)
                root = root.left
            if not stack:
                return self.res
            node = stack.pop()
            self.res.append(node.val)
            root = node.right
    def printResult(self):
        print(self.res)
    def main(self):
        # Create a binary tree and call inorderTraversal on it
        root = TreeNode(1)
        root.left = TreeNode(2)
        root.right = TreeNode(3)
        self.inorderTraversal(root)
        self.printResult()
if __name__ == '__main__':
    s = Solution()
    s.main()

