#include <iostream>
#include <vector>
#include <stack>
using namespace std;
class Solution {
    vector<int> res;
    stack<TreeNode*> stack;
    void inorderTraversal(TreeNode* root) {
        while (root || !stack.empty()) {
            while (root) {
                stack.push(root);
                root = root->left;
            }
            if (stack.empty()) {
                return;
            }
            root = stack.top();
            stack.pop();
            res.push_back(root->val);
            root = root->right;
        }
    }
    vector<int> inorderTraversal(TreeNode* root) {
        inorderTraversal(root);
        return res;
    }
};
int main() {
    Solution s;
    // Create a binary tree and call inorderTraversal on it
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    s.inorderTraversal(root);
    for (int i = 0; i < s.res.size(); ++i) {
        cout << s.res[i] << endl;
    }
    return 0;
}
